import React, { useEffect, useState } from "react";

function Dashboard({ onLogout }) {
  const [enquiries, setEnquiries] = useState([]);

  useEffect(() => {
    fetch("http://localhost:5000/api/enquiry")
      .then((res) => res.json())
      .then((data) => {
        setEnquiries(data);
      })
      .catch((err) => {
        console.error("Fetch error:", err);
      });
  }, []);

  return (
    <div style={{ padding: "20px" }}>
      {/* Header */}
      <div style={{ display: "flex", justifyContent: "space-between" }}>
        <h2>Client Enquiries</h2>
        <button
          onClick={onLogout}
          style={{
            padding: "6px 12px",
            backgroundColor: "red",
            color: "white",
            border: "none",
            borderRadius: "4px",
            cursor: "pointer",
            height: "35px",
          }}
        >
          Logout
        </button>
      </div>

      {/* Table */}
      {enquiries.length === 0 ? (
        <p>No enquiries found</p>
      ) : (
        <table
          border="1"
          cellPadding="8"
          cellSpacing="0"
          style={{ width: "100%", marginTop: "20px" }}
        >
          <thead>
            <tr>
              <th>Name</th>
              <th>Phone</th>
              <th>Location</th>
              <th>Service</th>
              <th>Message</th>
            </tr>
          </thead>
          <tbody>
            {enquiries.map((e) => (
              <tr key={e._id}>
                <td>{e.name}</td>
                <td>{e.phone}</td>
                <td>{e.location}</td>
                <td>{e.service}</td>
                <td>{e.message}</td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
}

export default Dashboard;
